public int findMaxLength(int[] nums) {
    int max_length = 0, zeroes = 0, ones = 0;
    HashMap<Integer, Integer> count_map = new HashMap<>();
    count_map.put(0, -1);

    for(int i = 0; i < nums.length; ++i) {
